    2220006: "@Refined Dustin Silver Knight Armor",
    2220007: "Refined Royal Knight Armor (Rental)",
    2220008: "Refined Royal Knight Armor",
    2220009: "Refined Dustin Silver Knight Armor",
    2220010: "Refined Royal Knight Armor",
